import { HttpClient, HttpHeaders } from "@angular/common/http";
import { ChangeDetectorRef, Component, OnInit } from "@angular/core";
import {
  FormBuilder,
  FormControl,
  FormGroup,
  Validators,
} from "@angular/forms";
import { AlertService } from "src/app/core/services/alert.service";
import { EnvService } from "src/app/core/services/env.service";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import { sortingService } from "src/app/core/services/sorting.service";
import { JobUsers } from "src/app/views/Models/Users/JobUsers";
import { Jobs } from "src/app/views/Models/Users/jobs";
import { OverlayEventDetail } from "../../registry/client-registration/overlays-interface";
import { pagingService } from "src/app/core/services/paging.service";
import { IBranch } from "src/app/views/Models/References/Branch";
import {
  Users,
  UsersSupervision,
} from "src/app/views/Models/Users/UserSupervision";
import { StaticRef } from "src/app/views/Models/References/StaticRef";

@Component({
  selector: "app-job-assign-users",
  templateUrl: "./job-assign-users.page.html",
  styleUrls: ["./job-assign-users.page.scss"],
})
export class JobAssignUsersPage implements OnInit {
  showLoader: boolean = false;
  isInsertFailed: boolean = false;
  details: boolean = false;

  pageSize: number; // number of viewed results
  page = 1; // the page we are viewing
  resultsCount; // the number of results
  totalPages = 1; // calculate by the pageSize and resultcount this.totalPages = (Math.trunc(x) < (this.resultsCount/this.pageSize)) ? Math.trunc(x)+1:Math.trunc(x) ;

  pageSizeForSupervised: number;
  pageForSupervised = 1;

  jobs: Jobs[] = [];
  users: JobUsers[] = [];
  filteredUsers: JobUsers[] = [];

  usersForSupervision: JobUsers[] = [];
  filteredUsersSupervised: JobUsers[] = [];

  UsersSupervisedChecked: Users[];

  supervisorUser: JobUsers;

  resultOfInsert;

  sortingIconClass: string;
  sortingIconParam: string;

  branches: IBranch[] = [];

  org_code_userinfo: string;
  job_id: string;
  constructor(
    private http: HttpClient,
    private formBuilder: FormBuilder,
    private alertService: AlertService,
    private env: EnvService,
    private authService: MohassilAuthService,
    private sortingService: sortingService,
    public pagingService: pagingService,
    private cdref: ChangeDetectorRef
  ) {}

  ngAfterContentChecked() {
    this.cdref.detectChanges();
  }

  AssignJobForm: FormGroup = this.formBuilder.group({
    job_code: ["", [Validators.required]],
  });

  SearchForm: FormGroup = this.formBuilder.group({
    search_input: [""],
    branch_code: [""],
    search_cur_job: [""],
  });

  SearchSupervisionForm: FormGroup = this.formBuilder.group({
    search_input: [""],
    search_cur_job: [""],
  });

  ngOnInit() {
    this.pageSize = this.pagingService.getPageSizeFromLocalStorage();
    this.pageSizeForSupervised =
      this.pagingService.getPageSizeFromLocalStorage();
    this.authService.getUserInfo().then((userInfo) => {
      this.org_code_userinfo = userInfo.org_code;
      this.job_id = userInfo.workflow_job_id;
      this.GetTreesAndJobsSupervised();
    });
    this.GetUsers();
  }

  GetTreesAndJobsSupervised() {
    this.showLoader = true;
    this.http
      .post<Jobs[]>(this.env.API_URL + "api/Job/GetTreesAndJobsSupervised", {
        org_code: this.org_code_userinfo,
        job_id: this.job_id,
      })
      .subscribe({
        next: (data) => {
          this.jobs = data;
          this.showLoader = false;
        },
        error: (err) => {
          console.log(err);
          this.showLoader = false;
        },
      });
  }

  GetUsers(): void {
    this.showLoader = true;
    this.http
      .get<JobUsers[]>(this.env.API_URL + `api/Job/GetJobUsers`)
      .subscribe({
        next: (data) => {
          this.users = data["entities"];
          this.branches = data["branches"];

          this.users.forEach((x) => (x.isCheck = false));

          this.filteredUsers = this.users;
          this.showLoader = false;
        },
        error: (err) => {
          console.log(err.message);
          this.showLoader = false;
        },
      });
  }

  sortingTable(data: any, param: string) {
    this.sortingService.sortByParameter(data, param);
    this.sortingIconClass =
      this.sortingService.sortOrder === "asc"
        ? "arrow-down-outline"
        : "arrow-up-outline";
    this.sortingIconParam = param;
  }

  get isAllSelected(): boolean {
    return this.filteredUsers.every((x) => x.isCheck);
  }

  get isAllSupervisedSelected(): boolean {
    return this.filteredUsersSupervised.every((x) => x.isCheck);
  }

  onCheckboxChange(event: any, user: any, index: any) {
    this.filteredUsers[index + this.pageSize * (this.page - 1)].isCheck =
      event.target.checked;

    // const i = this.users.findIndex((x) => x.user_name == user.user_name);
    // this.users[i].isCheck = event.target.checked;
  }

  onCheckboxSupervisedChange(event: any, user: any, index: any) {
    this.filteredUsersSupervised[
      index + this.pageSizeForSupervised * (this.pageForSupervised - 1)
    ].isCheck = event.target.checked;

    // console.log(this.filteredUsersSupervised);
    // const i = this.users.findIndex((x) => x.user_name == user.user_name);
    // this.users[i].isCheck = event.target.checked;
  }

  onCheckboxMasterChange(event: any) {
    if (event.target.checked) {
      this.filteredUsers.forEach(
        (user) => (user.isCheck = event.target.checked)
      );
    } else {
      if (this.isAllSelected) {
        this.filteredUsers.forEach(
          (user) => (user.isCheck = event.target.checked)
        );
      }
    }
  }

  supervisionCheckBoxMaster(event: any) {
    if (event.target.checked) {
      this.filteredUsersSupervised.forEach(
        (user) => (user.isCheck = event.target.checked)
      );
    } else {
      if (this.isAllSupervisedSelected) {
        this.filteredUsersSupervised.forEach(
          (user) => (user.isCheck = event.target.checked)
        );
      }
    }
  }

  searchForUsers() {
    this.page = 1;
    let user_name = this.SearchForm.value.search_input;
    let branch_code = this.SearchForm.value.branch_code;
    let search_cur_job = this.SearchForm.value.search_cur_job;

    this.filteredUsers = this.users.filter(
      (v) =>
        (user_name == "" ||
          v.user_name.toLowerCase().match(user_name.toLowerCase())) &&
        (search_cur_job == "" ||
          v.job_name?.toLowerCase().match(search_cur_job.toLowerCase())) &&
        (branch_code == "" || v.branch_code == branch_code)
    );
    // this.filteredUsers.forEach((x) => (x.isCheck = false));
  }

  searchForUsersSupervised() {
    this.page = 1;
    let user_name = this.SearchSupervisionForm.value.search_input;
    let search_cur_job = this.SearchSupervisionForm.value.search_cur_job;

    this.filteredUsersSupervised = this.usersForSupervision.filter(
      (v) =>
        (user_name == "" ||
          v.user_name.toLowerCase().match(user_name.toLowerCase())) &&
        (search_cur_job == "" ||
          v.job_name.toLowerCase().match(search_cur_job.toLowerCase()))
    );
    // this.filteredUsersSupervised.forEach((x) => (x.isCheck = false));
  }

  paging() {
    this.resultsCount = this.pagingService.totalCount;
    return this.pagingService.Paging(this.filteredUsers, this.page);
  }

  changePage(newPage: number): void {
    this.page = newPage;
  }

  changePageForSupervised(newPage: number): void {
    this.pageForSupervised = newPage;
  }

  async submitJobtoUser() {
    if (this.AssignJobForm.valid) {
      if (await this.alertService.SaveAlert()) {
        let users = this.filteredUsers.filter((x) => x.isCheck === true);
        if (users.length > 0) {
          this.showLoader = true;
          this.http
            .post(this.env.API_URL + `api/Job/InsertJobToUsers`, {
              org_code: this.org_code_userinfo.toString(),
              user_name: users.map((x) => x.user_name.toString()),
              branch_code: users.map((x) => x.branch_code.toString()),
              job_code: this.AssignJobForm.value.job_code.toString(),
            })
            .subscribe({
              next: (data) => {
                this.resultOfInsert = data;
                if (this.resultOfInsert.length == 0) {
                  this.alertService.showAlertConfirm("تم الحفظ بنجاح", true);
                } else {
                  this.alertService.showAlertError("فشل", false);
                  this.isInsertFailed = true;
                  console.log(this.resultOfInsert);
                }
                this.showLoader = false;
              },
              error: (err) => {
                this.alertService.showAlertError(err.error, false);
                this.showLoader = false;
              },
            });
        } else {
          this.alertService.showAlertError("لم يتم اختيار مستخدم", false);
        }
      }
    } else {
      this.alertService.showAlertError("يجب اختيار الوظيفة", false);
    }
  }

  clearForms() {
    this.isInsertFailed = false;
  }

  onWillDismiss(event: Event) {
    const ev = event as CustomEvent<OverlayEventDetail<string>>;
    if (ev.detail.role === "confirm") {
    }
  }

  dismissModal() {
    this.details = false;
  }

  clearSupervisionForm() {
    this.details = false;
    this.usersForSupervision = [];
    this.pageSizeForSupervised = 10;
    this.pageForSupervised = 1;
  }

  GetUsersForSupervision(user: JobUsers): void {
    this.showLoader = true;
    // this.pageSize = 10;
    // this.page = 1;
    this.supervisorUser = user;
    this.http
      .post(this.env.API_URL + `api/Job/GetJobUsersByJobID`, {
        branch_code: user.branch_code.toString(),
        job_id: user.job_id.toString(),
        user_name: user.user_name,
      })
      .subscribe({
        next: (data) => {
          this.usersForSupervision = data["result"];
          this.usersForSupervision.forEach((x) => (x.isCheck = false));
          this.filteredUsersSupervised = this.usersForSupervision;
          this.getJobUsersSupervision(user.user_name);

          this.details = true;
          this.showLoader = false;
        },
        error: (err) => {
          console.log(err.message);
          this.showLoader = false;
        },
      });
  }

  submitUsersSupervision() {
    // let users = this.filteredUsersSupervised.filter((x) => x.isCheck === true);
    this.UsersSupervisedChecked = this.filteredUsersSupervised.map((user) => ({
      supervisor_branch_code: this.supervisorUser.branch_code.toString(),
      supervisor_job_id: this.supervisorUser.job_id,
      supervisor_user_name: this.supervisorUser.user_name,
      supervised_branch_code: user.branch_code.toString(),
      supervised_job_id: user.job_id,
      supervised_user_name: user.user_name,
      isCheck: user.isCheck,
    }));
    var UsersSupervisionList: UsersSupervision = {
      org_code: this.org_code_userinfo,
      users: this.UsersSupervisedChecked,
    };
    this.sendUsersSupervision(UsersSupervisionList);
  }

  async sendUsersSupervision(usersSupervision: UsersSupervision) {
    console.log(usersSupervision);
    this.http
      .post(
        this.env.API_URL + `api/Job/InsertUsersSupervision`,
        usersSupervision
      )
      .subscribe({
        next: async (data) => {
          this.resultOfInsert = data;
          if (this.resultOfInsert.length == 0) {
            this.alertService.showAlertConfirm("تم الحفظ بنجاح", true);
          } else {
            this.alertService.showAlertError("فشل", false);
            this.isInsertFailed = true;
            console.log(this.resultOfInsert);
          }
          this.showLoader = false;
        },
        error: async (err) => {
          this.alertService.showAlertError(err.error, false);
          console.log(err);
          this.showLoader = false;
        },
      });
  }

  getJobUsersSupervision(user_name: string) {
    this.http
      .post<Users[]>(this.env.API_URL + `api/Job/GetJobUsersSupervision`, {
        user_name: user_name,
      })
      .subscribe({
        next: (data) => {
          this.UsersSupervisedChecked = data;
          this.UsersSupervisedChecked.forEach((x) => {
            x.isCheck = true;
          });
          this.filteredUsersSupervised.map((x) => {
            let supervised_user = this.UsersSupervisedChecked.find(
              (y) => y.supervised_user_name === x.user_name.toString()
            );
            if (
              supervised_user &&
              x.user_name === supervised_user.supervised_user_name
            ) {
              x.isCheck = true;
            }
          });
        },
        error: async (err) => {
          this.alertService.showAlertError(err.error, false);
          this.showLoader = false;
        },
      });
  }
}
